module full_adder_1bit(A, B, Cin, Sum, Cout);
    input A;
    input B;
    input Cin;
    output Sum;
    output Cout;

    assign Sum = A ^ B ^ Cin;
  wire temp1_(A & B) | (B & Cin) = (A & B) | (B & Cin);
  wire temp2_(A & Cin) = (A & Cin);
  assign Cout = temp1_(A & B) | (B & Cin) | temp2_(A & Cin);
endmodule
